-- Users table CREATE TABLE users ( id UUID PRIMARY KEY, login VARCHAR(255) NOT NULL UNIQUE, password_hash VARCHAR(255) NOT NULL, status VARCHAR(50) NOT NULL, role VARCHAR(50) NOT NULL, hardware_token_secret VARCHAR(255), failed_auth_attempts INTEGER DEFAULT 0, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP );
-- Messages table CREATE TABLE messages ( id UUID PRIMARY KEY, sender_id UUID NOT NULL, recipient_id UUID NOT NULL, group_id UUID, encrypted_payload TEXT NOT NULL, wrapped_message_key TEXT NOT NULL, ratchet_step INTEGER, signature VARCHAR(1024) NOT NULL, delivery_status VARCHAR(50) NOT NULL, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, FOREIGN KEY (sender_id) REFERENCES users(id), FOREIGN KEY (recipient_id) REFERENCES users(id) );
-- Group chats table CREATE TABLE group_chats ( id UUID PRIMARY KEY, name VARCHAR(255) NOT NULL, owner_id UUID NOT NULL, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, FOREIGN KEY (owner_id) REFERENCES users(id) );
-- Group members table CREATE TABLE group_members ( group_id UUID NOT NULL, member_id UUID NOT NULL, PRIMARY KEY (group_id, member_id), FOREIGN KEY (group_id) REFERENCES group_chats(id), FOREIGN KEY (member_id) REFERENCES users(id) );
-- File transfers table CREATE TABLE file_transfers ( id UUID PRIMARY KEY, sender_id UUID NOT NULL, recipient_id UUID NOT NULL, filename VARCHAR(255) NOT NULL, file_size_bytes BIGINT NOT NULL, message_key VARCHAR(1024) NOT NULL, checksum VARCHAR(64), delivery_status VARCHAR(50) NOT NULL, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, FOREIGN KEY (sender_id) REFERENCES users(id), FOREIGN KEY (recipient_id) REFERENCES users(id) );
-- Audit events table CREATE TABLE audit_events ( id UUID PRIMARY KEY, event_type VARCHAR(100) NOT NULL, actor VARCHAR(255), subject VARCHAR(1024), created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP );
-- Offline message queue table CREATE TABLE offline_queue ( recipient_id UUID NOT NULL, message_id UUID NOT NULL, PRIMARY KEY (recipient_id, message_id), FOREIGN KEY (recipient_id) REFERENCES users(id), FOREIGN KEY (message_id) REFERENCES messages(id) );
-- Encryption methods comparison table CREATE TABLE encryption_benchmarks ( id UUID PRIMARY KEY, method_name VARCHAR(100) NOT NULL, test_input_size_bytes INTEGER NOT NULL, encryption_time_ms BIGINT, decryption_time_ms BIGINT, ciphertext_size_bytes INTEGER, security_level VARCHAR(50), is_hardware_compatible BOOLEAN, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP );
-- Create indexes CREATE INDEX idx_messages_sender ON messages(sender_id); CREATE INDEX idx_messages_recipient ON messages(recipient_id); CREATE INDEX idx_messages_status ON messages(delivery_status); CREATE INDEX idx_audit_type ON audit_events(event_type); CREATE INDEX idx_audit_actor ON audit_events(actor); CREATE INDEX idx_offline_queue_recipient ON offline_queue(recipient_id); CREATE INDEX idx_file_transfers_sender ON file_transfers(sender_id); CREATE INDEX idx_group_members_group ON group_members(group_id);

package com.securemsg.api;

import com.securemsg.security.EncryptionComparisonService;
import com.securemsg.security.EncryptionComparisonService.EncryptionMethod;
import com.securemsg.security.EncryptionComparisonService.EncryptionTestResult;
import org.springframework.web.bind.annotation.*;

import java.util.*;

@RestController
@RequestMapping("/api/encryption")
public class EncryptionComparisonController {

    private final EncryptionComparisonService encryptionService = new EncryptionComparisonService();

    /**
     * Тестирует все методы шифрования на одинаковом входе
     */
    @PostMapping("/test-all")
    public Map<String, Object> testAllMethods(@RequestParam(defaultValue = "Hello confidential world! This is a test message for encryption comparison.") String plaintext) {
        List<EncryptionTestResult> results = new ArrayList<>();

        for (EncryptionMethod method : EncryptionMethod.values()) {
            EncryptionTestResult result = encryptionService.testEncryption(method, plaintext);
            results.add(result);
        }

        Map<String, Object> response = new LinkedHashMap<>();
        response.put("plaintext", plaintext);
        response.put("plaintextSize", plaintext.length());
        response.put("timestamp", System.currentTimeMillis());
        response.put("results", results);
        response.put("summary", generateSummary(results));

        return response;
    }

    /**
     * Тестирует конкретный метод шифрования
     */
    @PostMapping("/test/{method}")
    public Map<String, Object> testSingleMethod(
            @PathVariable String method,
            @RequestParam(defaultValue = "Test message for encryption") String plaintext) {

        try {
            EncryptionMethod encMethod = EncryptionMethod.valueOf(method.toUpperCase());
            EncryptionTestResult result = encryptionService.testEncryption(encMethod, plaintext);

            Map<String, Object> response = new LinkedHashMap<>();
            response.put("plaintext", plaintext);
            response.put("method", encMethod.displayName);
            response.put("result", result);
            response.put("info", EncryptionComparisonService.getMethodInfo(encMethod));

            return response;
        } catch (IllegalArgumentException e) {
            return Map.of("error", "Unknown method: " + method);
        }
    }

    /**
     * Возвращает информацию о конкретном методе
     */
    @GetMapping("/info/{method}")
    public Map<String, Object> getMethodInfo(@PathVariable String method) {
        try {
            EncryptionMethod encMethod = EncryptionMethod.valueOf(method.toUpperCase());
            return EncryptionComparisonService.getMethodInfo(encMethod);
        } catch (IllegalArgumentException e) {
            return Map.of("error", "Unknown method: " + method);
        }
    }

    /**
     * Возвращает список всех доступных методов
     */
    @GetMapping("/methods")
    public List<Map<String, Object>> getAllMethods() {
        List<Map<String, Object>> methods = new ArrayList<>();

        for (EncryptionMethod method : EncryptionMethod.values()) {
            Map<String, Object> methodInfo = new LinkedHashMap<>();
            methodInfo.put("name", method.name());
            methodInfo.put("displayName", method.displayName);
            methodInfo.put("description", method.description);
            methodInfo.put("isHardwareCompatible", method.isHardwareCompatible);
            methodInfo.put("securityLevel", method.securityLevel);

            // Добавляем из getMethodInfo
            Map<String, Object> fullInfo = EncryptionComparisonService.getMethodInfo(method);
            methodInfo.putAll(fullInfo);

            methods.add(methodInfo);
        }

        return methods;
    }

    /**
     * Сравнение двух методов
     */
    @PostMapping("/compare")
    public Map<String, Object> compareMethods(
            @RequestParam String method1,
            @RequestParam String method2,
            @RequestParam(defaultValue = "Test message for comparison") String plaintext) {

        try {
            EncryptionMethod m1 = EncryptionMethod.valueOf(method1.toUpperCase());
            EncryptionMethod m2 = EncryptionMethod.valueOf(method2.toUpperCase());

            EncryptionTestResult result1 = encryptionService.testEncryption(m1, plaintext);
            EncryptionTestResult result2 = encryptionService.testEncryption(m2, plaintext);

            Map<String, Object> comparison = new LinkedHashMap<>();
            comparison.put("method1", result1);
            comparison.put("method2", result2);
            comparison.put("comparison", Map.of(
                    "encryptionTimeDiff", result1.encryptionTimeMs - result2.encryptionTimeMs,
                    "decryptionTimeDiff", result1.decryptionTimeMs - result2.decryptionTimeMs,
                    "totalTimeDiff", result1.totalTimeMs - result2.totalTimeMs,
                    "ciphertextSizeDiff", result1.ciphertextSizeBytes - result2.ciphertextSizeBytes,
                    "faster", result1.totalTimeMs < result2.totalTimeMs ? "method1" : "method2",
                    "smaller", result1.ciphertextSizeBytes < result2.ciphertextSizeBytes ? "method1" : "method2"
            ));

            return comparison;
        } catch (IllegalArgumentException e) {
            return Map.of("error", "Unknown method");
        }
    }

    /**
     * Генерирует сводку результатов
     */
    private Map<String, Object> generateSummary(List<EncryptionTestResult> results) {
        Map<String, Object> summary = new LinkedHashMap<>();

        // Найти самый быстрый метод
        EncryptionTestResult fastest = results.stream()
                .filter(r -> !r.status.contains("ERROR"))
                .min(Comparator.comparingLong(r -> r.totalTimeMs))
                .orElse(null);

        // Найти самый компактный метод
        EncryptionTestResult mostCompact = results.stream()
                .filter(r -> !r.status.contains("ERROR"))
                .min(Comparator.comparingInt(r -> r.ciphertextSizeBytes))
                .orElse(null);

        // Найти самый безопасный метод
        EncryptionTestResult mostSecure = results.stream()
                .filter(r -> "EXCELLENT".equals(r.securityLevel))
                .findFirst()
                .orElse(null);

        summary.put("fastest", fastest != null ? Map.of(
                "method", fastest.methodName,
                "time", fastest.totalTimeMs + "ms"
        ) : "No suitable method");

        summary.put("mostCompact", mostCompact != null ? Map.of(
                "method", mostCompact.methodName,
                "size", mostCompact.ciphertextSizeBytes + " bytes",
                "overhead", String.format("%.1f%%", mostCompact.overheadPercent)
        ) : "No suitable method");

        summary.put("mostSecure", mostSecure != null ? Map.of(
                "method", mostSecure.methodName,
                "level", mostSecure.securityLevel
        ) : "No secure method found");

        // Рекомендуемый метод (баланс скорости, безопасности и компактности)
        summary.put("recommended", "AES-256-GCM - лучший баланс между скоростью, безопасностью и поддержкой аппаратного ускорения");

        return summary;
    }
}

package com.securemsg.security;

import org.bouncycastle.jce.provider.BouncyCastleProvider;
import javax.crypto.Cipher;
import javax.crypto.spec.SecretKeySpec;
import javax.crypto.spec.IvParameterSpec;
import java.nio.charset.StandardCharsets;
import java.security.Security;
import java.security.SecureRandom;
import java.util.Base64;
import java.util.HashMap;
import java.util.Map;

/**
 * Сравнение методов шифрования:
 * - AES-256-GCM (аппаратно ускоряемый, modern)
 * - AES-256-CBC (программный, безопасный)
 * - AES-128-CBC (слабее, быстрее)
 * - DES (уязвимый, историческое значение)
 * - ChaCha20 (современный, не требует IV как AES-GCM)
 * - RSA-4096 (асимметричный, медленный)
 * - Plaintext (для сравнения, опасный!)
 */
public class EncryptionComparisonService {

    static {
        Security.addProvider(new BouncyCastleProvider());
    }

    public enum EncryptionMethod {
        AES_256_GCM("AES-256-GCM", "Современный аппаратно-ускоренный стандарт", true, "EXCELLENT"),
        AES_256_CBC("AES-256-CBC", "Безопасный, программный, требует IV", false, "EXCELLENT"),
        AES_128_CBC("AES-128-CBC", "Слабее AES-256, но вполне безопасный", false, "GOOD"),
        DES_ECB("DES-ECB", "Уязвимый, только для демонстрации уязвимостей", false, "WEAK"),
        CHACHA20("ChaCha20", "Современный поток-ориентированный шифр", false, "EXCELLENT"),
        RSA_ECB("RSA-4096", "Асимметричный, медленный, для ключей", true, "EXCELLENT"),
        PLAINTEXT("PLAINTEXT", "БЕЗ ШИФРОВАНИЯ - опасно!", false, "NONE");

        public final String displayName;
        public final String description;
        public final boolean isHardwareCompatible;
        public final String securityLevel;

        EncryptionMethod(String displayName, String description, boolean isHardwareCompatible, String securityLevel) {
            this.displayName = displayName;
            this.description = description;
            this.isHardwareCompatible = isHardwareCompatible;
            this.securityLevel = securityLevel;
        }
    }

    /**
     * Запускает тест шифрования для указанного метода
     */
    public EncryptionTestResult testEncryption(EncryptionMethod method, String plaintext) {
        long startEncrypt = System.nanoTime();
        String ciphertext;
        int ciphertextSize = 0;

        try {
            switch (method) {
                case AES_256_GCM:
                    ciphertext = encryptAES256GCM(plaintext);
                    ciphertextSize = ciphertext.length();
                    break;
                case AES_256_CBC:
                    ciphertext = encryptAES256CBC(plaintext);
                    ciphertextSize = ciphertext.length();
                    break;
                case AES_128_CBC:
                    ciphertext = encryptAES128CBC(plaintext);
                    ciphertextSize = ciphertext.length();
                    break;
                case DES_ECB:
                    ciphertext = encryptDES(plaintext);
                    ciphertextSize = ciphertext.length();
                    break;
                case CHACHA20:
                    ciphertext = encryptChaCha20(plaintext);
                    ciphertextSize = ciphertext.length();
                    break;
                case RSA_ECB:
                    ciphertext = encryptRSA(plaintext);
                    ciphertextSize = ciphertext.length();
                    break;
                case PLAINTEXT:
                    ciphertext = plaintext;
                    ciphertextSize = plaintext.length();
                    break;
                default:
                    throw new IllegalArgumentException("Unknown method: " + method);
            }
        } catch (Exception e) {
            return new EncryptionTestResult(
                    method.name(),
                    plaintext.length(),
                    -1,
                    -1,
                    -1,
                    "ERROR: " + e.getMessage(),
                    method.isHardwareCompatible,
                    method.securityLevel
            );
        }

        long encryptTime = (System.nanoTime() - startEncrypt) / 1_000_000; // в миллисекундах

        long startDecrypt = System.nanoTime();
        String decrypted;
        try {
            switch (method) {
                case AES_256_GCM:
                    decrypted = decryptAES256GCM(ciphertext);
                    break;
                case AES_256_CBC:
                    decrypted = decryptAES256CBC(ciphertext);
                    break;
                case AES_128_CBC:
                    decrypted = decryptAES128CBC(ciphertext);
                    break;
                case DES_ECB:
                    decrypted = decryptDES(ciphertext);
                    break;
                case CHACHA20:
                    decrypted = decryptChaCha20(ciphertext);
                    break;
                case RSA_ECB:
                    decrypted = decryptRSA(ciphertext);
                    break;
                case PLAINTEXT:
                    decrypted = ciphertext;
                    break;
                default:
                    throw new IllegalArgumentException("Unknown method: " + method);
            }
        } catch (Exception e) {
            return new EncryptionTestResult(
                    method.name(),
                    plaintext.length(),
                    encryptTime,
                    -1,
                    ciphertextSize,
                    "DECRYPTION_FAILED: " + e.getMessage(),
                    method.isHardwareCompatible,
                    method.securityLevel
            );
        }

        long decryptTime = (System.nanoTime() - startDecrypt) / 1_000_000;

        boolean isValid = plaintext.equals(decrypted);
        String status = isValid ? "SUCCESS" : "INVALID_DECRYPTION";

        return new EncryptionTestResult(
                method.name(),
                plaintext.length(),
                encryptTime,
                decryptTime,
                ciphertextSize,
                status,
                method.isHardwareCompatible,
                method.securityLevel
        );
    }

    // ============ AES-256-GCM ============
    private String encryptAES256GCM(String plaintext) throws Exception {
        byte[] key = new byte[32];
        new SecureRandom().nextBytes(key);
        byte[] iv = new byte[12];
        new SecureRandom().nextBytes(iv);

        Cipher cipher = Cipher.getInstance("AES/GCM/NoPadding");
        cipher.init(Cipher.ENCRYPT_MODE, new SecretKeySpec(key, "AES"), new javax.crypto.spec.GCMParameterSpec(128, iv));
        byte[] ciphertext = cipher.doFinal(plaintext.getBytes(StandardCharsets.UTF_8));

        byte[] result = new byte[iv.length + ciphertext.length];
        System.arraycopy(iv, 0, result, 0, iv.length);
        System.arraycopy(ciphertext, 0, result, iv.length, ciphertext.length);

        return Base64.getEncoder().encodeToString(result);
    }

    private String decryptAES256GCM(String ciphertext) throws Exception {
        // For demo, we'll just return "fake" decryption to show the concept
        return "Decrypted[" + ciphertext.substring(0, Math.min(20, ciphertext.length())) + "...]";
    }

    // ============ AES-256-CBC ============
    private String encryptAES256CBC(String plaintext) throws Exception {
        byte[] key = new byte[32];
        new SecureRandom().nextBytes(key);
        byte[] iv = new byte[16];
        new SecureRandom().nextBytes(iv);

        Cipher cipher = Cipher.getInstance("AES/CBC/PKCS5Padding");
        cipher.init(Cipher.ENCRYPT_MODE, new SecretKeySpec(key, "AES"), new IvParameterSpec(iv));
        byte[] ciphertext = cipher.doFinal(plaintext.getBytes(StandardCharsets.UTF_8));

        byte[] result = new byte[iv.length + ciphertext.length];
        System.arraycopy(iv, 0, result, 0, iv.length);
        System.arraycopy(ciphertext, 0, result, iv.length, ciphertext.length);

        return Base64.getEncoder().encodeToString(result);
    }

    private String decryptAES256CBC(String ciphertext) {
        return "Decrypted[" + ciphertext.substring(0, Math.min(20, ciphertext.length())) + "...]";
    }

    // ============ AES-128-CBC ============
    private String encryptAES128CBC(String plaintext) throws Exception {
        byte[] key = new byte[16];
        new SecureRandom().nextBytes(key);
        byte[] iv = new byte[16];
        new SecureRandom().nextBytes(iv);

        Cipher cipher = Cipher.getInstance("AES/CBC/PKCS5Padding");
        cipher.init(Cipher.ENCRYPT_MODE, new SecretKeySpec(key, "AES"), new IvParameterSpec(iv));
        byte[] ciphertext = cipher.doFinal(plaintext.getBytes(StandardCharsets.UTF_8));

        byte[] result = new byte[iv.length + ciphertext.length];
        System.arraycopy(iv, 0, result, 0, iv.length);
        System.arraycopy(ciphertext, 0, result, iv.length, ciphertext.length);

        return Base64.getEncoder().encodeToString(result);
    }

    private String decryptAES128CBC(String ciphertext) {
        return "Decrypted[" + ciphertext.substring(0, Math.min(20, ciphertext.length())) + "...]";
    }

    // ============ DES (уязвимый!) ============
    private String encryptDES(String plaintext) throws Exception {
        // DES use only 8-byte key (56-bit)
        byte[] key = "12345678".getBytes(StandardCharsets.UTF_8);
        byte[] iv = new byte[8];
        new SecureRandom().nextBytes(iv);

        Cipher cipher = Cipher.getInstance("DES/CBC/PKCS5Padding");
        cipher.init(Cipher.ENCRYPT_MODE, new SecretKeySpec(key, 0, 8, "DES"), new IvParameterSpec(iv));
        byte[] ciphertext = cipher.doFinal(plaintext.getBytes(StandardCharsets.UTF_8));

        byte[] result = new byte[iv.length + ciphertext.length];
        System.arraycopy(iv, 0, result, 0, iv.length);
        System.arraycopy(ciphertext, 0, result, iv.length, ciphertext.length);

        return Base64.getEncoder().encodeToString(result);
    }

    private String decryptDES(String ciphertext) {
        return "Decrypted[" + ciphertext.substring(0, Math.min(20, ciphertext.length())) + "...]";
    }

    // ============ ChaCha20 ============
    private String encryptChaCha20(String plaintext) throws Exception {
        byte[] key = new byte[32];
        new SecureRandom().nextBytes(key);
        byte[] nonce = new byte[12];
        new SecureRandom().nextBytes(nonce);

        // Using BouncyCastle ChaCha20
        byte[] ciphertext = plaintext.getBytes(StandardCharsets.UTF_8);
        // Dummy encryption for demo
        return Base64.getEncoder().encodeToString(ciphertext);
    }

    private String decryptChaCha20(String ciphertext) {
        return "Decrypted[" + ciphertext.substring(0, Math.min(20, ciphertext.length())) + "...]";
    }

    // ============ RSA (асимметричный) ============
    private String encryptRSA(String plaintext) throws Exception {
        // For demo, just return base64
        return Base64.getEncoder().encodeToString(plaintext.getBytes(StandardCharsets.UTF_8));
    }

    private String decryptRSA(String ciphertext) {
        return "Decrypted[" + ciphertext.substring(0, Math.min(20, ciphertext.length())) + "...]";
    }

    /**
     * DTO для результатов тестирования
     */
    public static class EncryptionTestResult {
        public final String methodName;
        public final int plaintextSizeBytes;
        public final long encryptionTimeMs;
        public final long decryptionTimeMs;
        public final int ciphertextSizeBytes;
        public final String status;
        public final boolean isHardwareCompatible;
        public final String securityLevel;
        public final long totalTimeMs;
        public final double overheadPercent;

        public EncryptionTestResult(
                String methodName, int plaintextSizeBytes, long encryptionTimeMs,
                long decryptionTimeMs, int ciphertextSizeBytes, String status,
                boolean isHardwareCompatible, String securityLevel) {
            this.methodName = methodName;
            this.plaintextSizeBytes = plaintextSizeBytes;
            this.encryptionTimeMs = encryptionTimeMs;
            this.decryptionTimeMs = decryptionTimeMs;
            this.ciphertextSizeBytes = ciphertextSizeBytes;
            this.status = status;
            this.isHardwareCompatible = isHardwareCompatible;
            this.securityLevel = securityLevel;
            this.totalTimeMs = encryptionTimeMs + decryptionTimeMs;
            this.overheadPercent = plaintextSizeBytes > 0 ? ((double)ciphertextSizeBytes / plaintextSizeBytes - 1) * 100 : 0;
        }
    }

    /**
     * Возвращает информацию о всех методах
     */
    public static Map<String, Object> getMethodInfo(EncryptionMethod method) {
        Map<String, Object> info = new HashMap<>();
        info.put("name", method.displayName);
        info.put("description", method.description);
        info.put("isHardware", method.isHardwareCompatible);
        info.put("securityLevel", method.securityLevel);

        // Добавим слабости каждого метода
        switch (method) {
            case AES_256_GCM:
                info.put("strengths", new String[]{"Аппаратное ускорение", "AEAD (authenticated)", "Modern standard"});
                info.put("weaknesses", new String[]{"Требует IV", "Сложнее для реализации"});
                info.put("recommended", true);
                break;
            case AES_256_CBC:
                info.put("strengths", new String[]{"Безопасный", "Широко поддерживается", "Проверенный стандарт"});
                info.put("weaknesses", new String[]{"Требует внешней аутентификации", "Медленнее AES-GCM"});
                info.put("recommended", true);
                break;
            case AES_128_CBC:
                info.put("strengths", new String[]{"Быстрее AES-256", "Достаточно безопасный"});
                info.put("weaknesses", new String[]{"128-bit ключ уязвим для квантовых компьютеров", "Брутфорс возможен при больших вычислениях"});
                info.put("recommended", false);
                break;
            case DES_ECB:
                info.put("strengths", new String[]{"Исторический интерес", "Очень быстрый"});
                info.put("weaknesses", new String[]{"56-bit ключ легко подбирается", "ECB mode опасен (паттерны)", "УСТАРЕЛ - НИКОГДА НЕ ИСПОЛЬЗОВАТЬ"});
                info.put("recommended", false);
                break;
            case CHACHA20:
                info.put("strengths", new String[]{"Современный", "Быстрый потоком", "Не требует IV"});
                info.put("weaknesses", new String[]{"Менее аппаратно ускорен чем AES", "Новее (может быть меньше проверок)"});
                info.put("recommended", true);
                break;
            case RSA_ECB:
                info.put("strengths", new String[]{"Асимметричный", "Для обмена ключами", "Аутентификация"});
                info.put("weaknesses", new String[]{"ОЧЕНЬ медленный", "Можно шифровать только маленькие данные", "Размер ключа > 4KB"});
                info.put("recommended", false);
                break;
            case PLAINTEXT:
                info.put("strengths", new String[]{"Нет никаких"});
                info.put("weaknesses", new String[]{"ПОЛНОСТЬЮ НЕБЕЗОПАСНО", "Видно всем", "Не применять никогда!"});
                info.put("recommended", false);
                break;
        }
        return info;
    }
}
